import React, { useState } from 'react';
import axios from 'axios';

function App() {
  const [id, setId] = useState('');
  const [name, setName] = useState('');

  const enrollUser = async () => {
    try {
      await axios.post('http://localhost:3001/enroll', { id, name });
      alert('User enrolled successfully');
    } catch (error) {
      alert('Failed to enroll user');
    }
  };

  const checkUser = async () => {
    try {
      await axios.post('http://localhost:3001/check', { id });
      alert('Fingerprint match found');
    } catch (error) {
      alert('No match found');
    }
  };

  return (
    <div className="App">
      <h1>Fingerprint Enrollment and Verification</h1>
      <div>
        <input
          type="text"
          placeholder="User ID"
          value={id}
          onChange={(e) => setId(e.target.value)}
        />
        <input
          type="text"
          placeholder="User Name"
          value={name}
          onChange={(e) => setName(e.target.value)}
        />
        <button onClick={enrollUser}>Enroll User</button>
      </div>
      <div>
        <input
          type="text"
          placeholder="User ID to Check"
          value={id}
          onChange={(e) => setId(e.target.value)}
        />
        <button onClick={checkUser}>Check Fingerprint</button>
      </div>
    </div>
  );
}

export default App;
